package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/exec"
	"os/signal"
	"syscall"

	"github.com/joho/godotenv"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/router"
	"github.com/ketang/flotsam/api/internal/server"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	withWorker := flag.Bool("with-worker", false, "fork flotsam-worker --watch as a child process")
	flag.Parse()

	// 1. Load .env (no-op if file is absent — dev convenience only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam api",
		"version", version.Version,
		"build_time", version.BuildTime,
		"env", cfg.Env,
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error
	}
	defer pool.Close()

	// 5. Initialize S3 storage client (optional)
	var store *storage.Client
	if cfg.S3Endpoint != "" {
		store, err = storage.New(storage.Config{
			Endpoint:       cfg.S3Endpoint,
			Bucket:         cfg.S3Bucket,
			AccessKey:      cfg.S3AccessKey,
			SecretKey:      cfg.S3SecretKey,
			Region:         cfg.S3Region,
			ForcePathStyle: cfg.S3ForcePathStyle,
		})
		if err != nil {
			slog.Error("failed to initialize storage", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error
		}
		slog.Info("storage: S3 client initialized", "endpoint", cfg.S3Endpoint, "bucket", cfg.S3Bucket)
	} else {
		slog.Warn("storage: S3_ENDPOINT not set, object storage disabled")
	}

	// 6. Initialize River client (insert-only — no workers, no queues)
	riverClient, err := river.NewClient(riverpgxv5.New(pool), &river.Config{})
	if err != nil {
		slog.Error("failed to create river client", "error", err)
		os.Exit(1)
	}
	slog.Info("river: insert-only client initialized")

	// 7. Initialize auth validator
	validator := auth.NewHMACValidator(cfg.JWTSecret)
	slog.Info("auth: using HS256 JWT validator")

	// 8. Initialize services
	itemService := item.New(pool)
	userService := user.New(pool)
	issuer := auth.NewIssuer(cfg.JWTSecret, cfg.JWTExpiry)

	// 9. Build router
	r := router.New(router.Deps{
		Config:      cfg,
		Pool:        pool,
		Validator:   validator,
		Storage:     store,
		RiverClient: riverClient,
		Items:       itemService,
		Users:       userService,
		Issuer:      issuer,
	})

	// 9. Optionally fork worker as child process
	var workerCmd *exec.Cmd
	if *withWorker {
		workerCmd = exec.Command("flotsam-worker", "--watch")
		workerCmd.Stdout = os.Stdout
		workerCmd.Stderr = os.Stderr
		if err := workerCmd.Start(); err != nil {
			slog.Error("failed to start worker", "error", err)
		} else {
			slog.Info("worker: started as child process", "pid", workerCmd.Process.Pid)
		}
	}

	// 10. Start HTTP server
	srv := server.New(cfg.Addr(), r)

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.Start(); err != nil {
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 11. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 12. Graceful shutdown
	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	slog.Info("server: shutting down", "timeout", cfg.ShutdownTimeout)
	if err := srv.Shutdown(shutdownCtx); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}

	// Kill worker child process if running
	if workerCmd != nil && workerCmd.Process != nil {
		slog.Info("worker: stopping child process", "pid", workerCmd.Process.Pid)
		_ = workerCmd.Process.Signal(syscall.SIGTERM)
		_ = workerCmd.Wait()
	}

	slog.Info("server: shutdown complete")
}

package auth

import (
	"fmt"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

// Issuer creates signed JWT tokens.
type Issuer struct {
	secret   []byte
	duration time.Duration
}

// NewIssuer creates a new token issuer with the given HMAC secret and token duration.
func NewIssuer(secret string, duration time.Duration) *Issuer {
	return &Issuer{
		secret:   []byte(secret),
		duration: duration,
	}
}

// Issue creates and signs a new JWT for the given user.
func (iss *Issuer) Issue(userID uuid.UUID, email, clientType string) (string, error) {
	now := time.Now()
	claims := &Claims{
		UserID:     userID,
		Email:      email,
		ClientType: clientType,
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   userID.String(),
			IssuedAt:  jwt.NewNumericDate(now),
			ExpiresAt: jwt.NewNumericDate(now.Add(iss.duration)),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signed, err := token.SignedString(iss.secret)
	if err != nil {
		return "", fmt.Errorf("auth: issue token: %w", err)
	}
	return signed, nil
}

package db

import (
	"context"
	"database/sql"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	_ "github.com/jackc/pgx/v5/stdlib"
	"github.com/ketang/flotsam/api/migrations"
	"github.com/pressly/goose/v3"
)

const maxConnectAttempts = 3

// Connect creates a pgxpool.Pool, pings the database, and returns the pool.
// It retries up to maxConnectAttempts times with exponential backoff.
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, fmt.Errorf("db: failed to parse database URL: %w", err)
	}

	var pool *pgxpool.Pool
	for attempt := 1; attempt <= maxConnectAttempts; attempt++ {
		pool, err = pgxpool.NewWithConfig(ctx, cfg)
		if err != nil {
			slog.Warn("db: connect attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		if err = pool.Ping(ctx); err != nil {
			pool.Close()
			slog.Warn("db: ping attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		stat := pool.Stat()
		slog.Info("db: connected",
			"attempt", attempt,
			"max_conns", stat.MaxConns(),
		)
		return pool, nil
	}

	return nil, fmt.Errorf("db: failed to connect after %d attempts: %w", maxConnectAttempts, err)
}

// newProvider creates a goose Provider instance using the embedded migrations.
func newProvider(db *sql.DB) (*goose.Provider, error) {
	provider, err := goose.NewProvider(goose.DialectPostgres, db, migrations.FS)
	if err != nil {
		return nil, fmt.Errorf("migrate: create provider: %w", err)
	}
	return provider, nil
}

// MigrateUp runs all pending goose UP migrations embedded in the binary.
func MigrateUp(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: running up migrations")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	provider, err := newProvider(db)
	if err != nil {
		return err
	}

	results, err := provider.Up(ctx)
	if err != nil {
		slog.Error("migrate: up failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: up: %w", err)
	}

	slog.Info("migrate: up completed",
		"applied", len(results),
		"duration_ms", time.Since(start).Milliseconds(),
	)
	return nil
}

// MigrateDown rolls back the most recent goose migration.
func MigrateDown(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: rolling back last migration")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	provider, err := newProvider(db)
	if err != nil {
		return err
	}

	result, err := provider.Down(ctx)
	if err != nil {
		slog.Error("migrate: down failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: down: %w", err)
	}

	if result != nil {
		slog.Info("migrate: down completed",
			"rolled_back", result.Source.Path,
			"duration_ms", time.Since(start).Milliseconds(),
		)
	} else {
		slog.Info("migrate: no migrations to roll back")
	}
	return nil
}

